"use client";

import { useEffect, useState } from "react";
import { GoogleAuthProvider, onIdTokenChanged, signInWithPopup, signInWithRedirect } from "firebase/auth";
import { auth } from "../../../lib/firebase";
export function withAdminAuthHeaders(token, options) {
  return {
    ...options,
    headers: {
      ...(options?.headers || {}),
      Authorization: `Bearer ${token}`
    }
  };
}
export default function useBattlefieldBriefAdminAuth() {
  const [authChecked, setAuthChecked] = useState(false);
  const [authed, setAuthed] = useState(false);
  const [token, setToken] = useState(null);
  const [user, setUser] = useState(null);
  const [error, setError] = useState(null);
  useEffect(() => {
    const unsub = onIdTokenChanged(auth, async nextUser => {
      setUser(nextUser);
      if (!nextUser) {
        setToken(null);
        setAuthed(false);
        setAuthChecked(true);
        return;
      }
      try {
        const nextToken = await nextUser.getIdToken();
        const res = await fetch("/api/admin/battlefield-briefs?limit=1", withAdminAuthHeaders(nextToken));
        if (!res.ok) {
          setAuthed(false);
          setToken(null);
          setError("Your account does not have admin access.");
          setAuthChecked(true);
          return;
        }
        setToken(nextToken);
        setAuthed(true);
        setError(null);
      } catch {
        setToken(null);
        setAuthed(false);
        setError("Unable to verify admin access.");
      } finally {
        setAuthChecked(true);
      }
    });
    return () => unsub();
  }, []);
  async function signIn() {
    setError(null);
    const provider = new GoogleAuthProvider();
    try {
      await signInWithPopup(auth, provider);
    } catch (err) {
      const code = typeof err === "object" && err && "code" in err ? String(err.code) : "";
      if (code === "auth/popup-blocked" || code === "auth/popup-closed-by-user") {
        await signInWithRedirect(auth, provider);
        return;
      }
      setError("Sign-in failed. Please try again.");
    }
  }
  async function signOut() {
    await auth.signOut();
    setToken(null);
    setAuthed(false);
  }
  return {
    authChecked,
    authed,
    token,
    user,
    error,
    signIn,
    signOut
  };
}